const msg = ($input.first().json.chatInput || '').toLowerCase();

const images = {
  photo: {
    type_image: "photo",
    presence_texte: false,
    complexite: "élevée",
    couleurs: "nombreuses",
    entropy: 7.85,
    taille_kb: 5200
  },
  screenshot: {
    type_image: "screenshot",
    presence_texte: true,
    complexite: "faible",
    couleurs: "peu nombreuses",
    entropy: 2.75,
    taille_kb: 1100
  },
  document: {
    type_image: "document",
    presence_texte: true,
    complexite: "faible",
    couleurs: "peu nombreuses",
    entropy: 3.12,
    taille_kb: 980
  },
  graphique: {
    type_image: "graphique",
    presence_texte: true,
    complexite: "moyenne",
    couleurs: "quelques-unes",
    entropy: 4.90,
    taille_kb: 420
  }
};

let f;
if      (msg.includes('photo'))      f = images.photo;
else if (msg.includes('screenshot')) f = images.screenshot;
else if (msg.includes('document'))   f = images.document;
else if (msg.includes('graphique'))  f = images.graphique;
else                                  f = images.screenshot;

return [{ json: f }];

