function parseOutput(item) {
  if (typeof item.output === "string") {
    try {
      return JSON.parse(item.output);
    } catch {
      return {};
    }
  }
  return item;
}

const llm1 = parseOutput($input.first().json);
const llm2 = parseOutput($input.last().json);

// score pertinence
function score(p) {
  if (!p) return 0;
  p = p.toLowerCase();
  if (p.includes("élevée")) return 3;
  if (p.includes("moyenne")) return 2;
  if (p.includes("faible")) return 1;
  return 0;
}

const score1 = score(llm1.pertinence);
const score2 = score(llm2.pertinence);

// priorité formats
function formatScore(format) {
  if (!format) return 0;
  format = format.toLowerCase();
  if (format === "avif") return 4;   // 🔥 الأفضل
  if (format === "webp") return 3;
  if (format === "jpeg") return 2;
  if (format === "png") return 1;
  return 0;
}

let decision;
let source;
let raison;

// 🧠 1: pertinence أولاً
if (score1 > score2) {
  decision = llm1;
  source = "LLM1";
  raison = "Pertinence plus élevée";
} else if (score2 > score1) {
  decision = llm2;
  source = "LLM2";
  raison = "Pertinence plus élevée";
}

// 🧠 2: نفس pertinence → اختار format ذكي
else {
  const f1 = formatScore(llm1.format);
  const f2 = formatScore(llm2.format);

  if (f1 > f2) {
    decision = llm1;
    source = "LLM1";
    raison = "Format plus optimisé (AVIF/WebP)";
  } else if (f2 > f1) {
    decision = llm2;
    source = "LLM2";
    raison = "Format plus optimisé (AVIF/WebP)";
  } else {
    decision = llm1;
    source = "LLM1";
    raison = "Choix par défaut";
  }
}

return [{
  json: {
    decision_finale: {
      format: decision.format,
      qualite: decision.qualite
    },
    source,
    raison,
    detail: {
      llm1,
      llm2
    }
  }
}];
